class CustomError(Exception):
    """Custom exception class."""
    pass

try:
    # Code that may raise an exception
    if condition:
        raise CustomError("Error message")
except CustomError as error_variable:
    # Handle specific custom exception
    print(error_variable)
except Exception as general_error:
    # Handle any other standard exception
    print(general_error)
else:
    # Execute if no exception was raised in the try block
    print("Success!")
finally:
    # Always execute, regardless of exceptions
    print("Cleanup operations")

