class DatabaseConnectionError(Exception):
    """Raised when the database connection fails."""
    pass

class TransactionFailedError(Exception):
    """Raised when a database transaction cannot be completed."""
    pass

class DatabaseService:
    def __init__(self, is_connected=True):
        self.is_connected = is_connected

    def execute_withdrawal(self, balance, amount):
        if not self.is_connected:
            raise DatabaseConnectionError("Lost connection to database server.")
        if amount > balance:
            raise TransactionFailedError(f"Insufficient funds. Balance: {balance}, Requested: {amount}")
        return balance - amount

def process_withdrawal(db_service, balance, amount):
    print("--- Starting Transaction ---")
    try:
        new_balance = db_service.execute_withdrawal(balance, amount)
    except DatabaseConnectionError as e:
        print(f"[LOG] Connection Error: {e}. Retrying connection...")
        return None
    except TransactionFailedError as e:
        print(f"[LOG] Transaction Aborted: {e}")
        raise  # Re-raising to let caller handle or log further
    else:
        print(f"[LOG] Transaction successful. New balance: {new_balance}")
        return new_balance
    finally:
        print("[CLEANUP] Closing database resources and releasing locks.")

# Test Case 1: Successful Transaction
db = DatabaseService(is_connected=True)
process_withdrawal(db, 500, 100)

# Test Case 2: Insufficient Funds (Raises TransactionFailedError and re-raises)
try:
    process_withdrawal(db, 500, 600)
except TransactionFailedError:
    print("[CALLER] Caught the re-raised TransactionFailedError.")

