def parse_integer(s):
    try:
        return int(s)
    except ValueError:
        return None

def get_percentage(part, total):
    try:
        return (part / total) * 100
    except ZeroDivisionError:
        return 0.0
    except TypeError:
        return None

class InvalidAgeError(Exception):
    pass

def verify_age(age):
    if age < 0 or age > 120:
        raise InvalidAgeError("Age must be between 0 and 120")
    return True

def fetch_config(config_dict, key, default):
    try:
        value = config_dict[key]
    except KeyError:
        return default
    else:
        return value

class LibraryError(Exception):
    pass

class BookNotAvailableError(LibraryError):
    pass

class UserBlockedError(LibraryError):
    pass

def borrow_book(book_status, user_status):
    if book_status == 'checked_out':
        raise BookNotAvailableError("The requested book is currently checked out.")
    if user_status == 'blocked':
        raise UserBlockedError("The user is blocked from borrowing books.")
    return "Book borrowed successfully!"

def process_data(data_list):
    try:
        total = 0
        for item in data_list:
            total += item
        return total
    except TypeError:
        print("Logging type error...")
        raise

import json

class MalformedConfigError(Exception):
    pass

def load_config(filepath):
    file = None
    try:
        file = open(filepath, 'r')
        return json.load(file)
    except FileNotFoundError:
        return {}
    except json.JSONDecodeError as e:
        raise MalformedConfigError(f"Invalid JSON format: {e}") from e
    finally:
        if file is not None:
            file.close()

